#!/usr/bin/env python3
import base64, os
target = os.path.expanduser("~/insideedge")
os.makedirs(target, exist_ok=True)
FILES = {
    "app.py": """""",
    "data.py": """""",
}
for fn, b64 in FILES.items():
    path = os.path.join(target, fn)
    with open(path, "wb") as f: f.write(base64.b64decode(b64))
    print(f"Wrote {path}")
print("Done. Now: cd ~/insideedge && git add . && git commit -m fix && git push")